void procesarPuntuaciones() {
    int numCasos;
    std::cin >> numCasos;
    while (numCasos--) {
        int maximo = INT_MIN;
        int conteoMaximo = 0;
        int puntuacion;
        while (std::cin >> puntuacion && puntuacion != 0) {
            if (puntuacion > maximo) {
                maximo = puntuacion;
                conteoMaximo = 1;
            } else if (puntuacion == maximo) {
                conteoMaximo++;
            }
        }
        std::cout << maximo << " " << conteoMaximo << std::endl;
    }
}
